# Rename columns and set row names
colnames(coords_data) <- c("Individual_ID", "long", "lat")
rownames(coords_data) <- coords_data$Individual_ID
coords_data <- coords_data[, c("long", "lat")]


# --- 2. DATA PROCESSING ---

# Read the tree
tree <- read.tree(text=newick_string)

# Identify outgroups/tips in the tree but not in the coordinates
missing_tips <- setdiff(tree$tip.label, rownames(coords_data))

if (length(missing_tips) > 0) {
    cat("Warning: The following tips were found in the tree but not in the coordinates and will be pruned:\n")
    cat(paste(missing_tips, collapse = ", "), "\n")
    
    # Prune the tree to only include tips with coordinates
    tree_sub <- drop.tip(tree, missing_tips)
    
    # Prune coordinates to only include tips present in the new tree
    coords_sub <- coords_data[tree_sub$tip.label, ]
} else {
    tree_sub <- tree
    coords_sub <- coords_data
}

# --- 3. CREATE PHYLO.TO.MAP OBJECT ---

# The coordinates are very close, indicating a small island/local region.
# We use the higher resolution 'worldHires' database for better detail.
cat("\nCreating phylo.to.map object (this may take a moment)...\n")
phymap_object <- phylo.to.map(
    tree_sub, 
    coords_sub, 
    plot = FALSE, 
    direction = "rightwards", 
    database = "worldHires"
)

# --- 4. GENERATE SPECTACULAR PLOT (TYPE="DIRECT") ---

# Define plot limits based on the narrow geographic range of your samples
# Longitude range: ~55.3 to ~55.7
# Latitude range: ~-21.3 to ~-20.9
x_limits <- c(55.3, 55.7)
y_limits <- c(-21.3, -20.9) 

# Start PDF device for high-quality output
pdf("phylogeographic_figure1_direct.pdf", width=12, height=10)

# Plotting the figure with customized aesthetics
plot(
    phymap_object,
    # Plotting parameters
    type = "direct", 
    direction = "rightwards",
    
    # Map Limits (crucial for local detail)
    xlim = x_limits, 
    ylim = y_limits,
    
    # Aesthetic settings
    fsize = 0.5,             # Font size for tip labels
    ftype = "i",             # Italic font for tip labels
    lwd = 2,                 # Line width for branches
    map.bg = "lightblue",    # Ocean color
    map.fill = "lightgreen", # Land color (Use a professional color)
    colors = "firebrick3",   # Phylogeographic connection color (dark red for contrast)
    pts = TRUE,              # Show geographic points
    cex.points = 1.2,        # Size of the points
    delimit_map = TRUE,      # Use the updated feature to clip map
    mar = c(3, 3, 3, 1)      # Margins: bottom, left, top, right
)

# Add a title
title(
    main = "Phylogenetic Relationships Projected onto Geographic Space (Réunion Island)", 
    cex.main = 1.2, 
    font.main = 2
)

# Add axes labels
mtext(
    "Longitude", 
    side = 1, 
    line = 2, 
    cex = 1.0
)
mtext(
    "Latitude", 
    side = 2, 
    line = 2, 
    cex = 1.0
)

# Close the PDF device
dev.off() 
cat("\n✅ Plot saved successfully as 'phylogeographic_figure1_direct.pdf'.\n")
